const raw = $input.first().json.chatInput || '';
const txt = raw.toLowerCase().trim();
const sessionId = String($input.first().json.sessionId || '').trim();
const staticData = $getWorkflowStaticData('global');
if (!staticData.ragSessions || typeof staticData.ragSessions !== 'object') staticData.ragSessions = {};
const ragSessions = staticData.ragSessions;
const resetRag = /\b(reset|end|exit|stop)\s+(rag|conversation|chat|session)\b/.test(txt) || /\b(new session|new conversation|reset chat|reset session)\b/.test(txt);
if (sessionId && resetRag) {
  delete ragSessions[sessionId];
  return [{ json: { flow: 'rag_end', customer_id: null, chatInput: raw, sessionId, rag_locked: false, rag_reset: true } }];
}
const ragLocked = Boolean(sessionId && ragSessions[sessionId]);
const custMatch = raw.match(/\b(\d{4,6})\b/);
const customer_id = custMatch ? custMatch[1] : null;
const hasCustomerId = Boolean(customer_id);
const isExistingLoan = /payment|missed|overdue|balance|loan.?status|delinquent|servicing|existing.?loan/.test(txt);
const isCompliance = /\baml\b|\bkyc\b|suspicious|\bsar\b|compliance|fraud|risk.?review|regulatory/.test(txt);
const isRagDiscovery = !hasCustomerId && /(what .*tables?|which .*tables?|available views?|available tables?|top\s*\d+|highest|largest|lowest|smallest|best rates?|loan related|approved loans?|rejected loans?|show .*loans|find .*loans|list .*loans|loan amount|interest rate|what rates?)/.test(txt);
const isInvestigation = !hasCustomerId && /find|search|which customers?|who mentioned|show .*cases|complaints? about|transcripts? about|similar complaints?|cases? involving|meeting notes|officer transcripts?|source.?of.?funds|competitor rate|escrow shortage|complaint patterns?|transcript patterns?/.test(txt);
let flow = 'new_loan';
if (ragLocked) {
  flow = 'rag_discovery';
} else if (isExistingLoan) {
  flow = 'existing_loan';
} else if (isCompliance) {
  flow = 'compliance';
} else if (isRagDiscovery) {
  flow = 'rag_discovery';
  if (sessionId) ragSessions[sessionId] = true;
} else if (isInvestigation) {
  flow = 'investigation';
}
return [{ json: {
  flow,
  customer_id,
  chatInput: raw,
  sessionId,
  rag_locked: flow === 'rag_discovery' && (ragLocked || Boolean(sessionId && ragSessions[sessionId])),
  rag_session_warning: flow === 'rag_discovery' && !sessionId ? 'No sessionId found; RAG session pinning will not persist.' : ''
} }];

const combined = $input.first().json.combined || '';
const pick = (regex, fallback = 'UNKNOWN') => {
  const match = combined.match(regex);
  return match ? match[1].trim() : fallback;
};
const customerId = pick(/customer_id:\s*([^\n]+)/i, $json.customer_id ? String($json.customer_id) : 'UNKNOWN');
const fullName = pick(/full_name:\s*([^\n]+)/i);
const loanAmount = pick(/loan_amount:\s*([^\n]+)/i);
const creditVerdict = pick(/credit_verdict:\s*([^\n]+)/i);
const paymentVerdict = pick(/payment_verdict:\s*([^\n]+)/i);
const propertyVerdict = pick(/property_verdict:\s*([^\n]+)/i);
const ltvRatio = pick(/ltv_ratio:\s*([^\n]+)/i);
const signals = [];
if (/WEAK|INSUFFICIENT_DATA/i.test(creditVerdict)) signals.push('credit_verdict: ' + creditVerdict);
if (/WEAK|INSUFFICIENT_DATA/i.test(paymentVerdict) || /payment_reliability:\s*High Risk/i.test(combined)) signals.push('payment_verdict: ' + paymentVerdict);
if (/WEAK|INSUFFICIENT_DATA/i.test(propertyVerdict)) signals.push('property_verdict: ' + propertyVerdict);
if (/^UNKNOWN$/i.test(ltvRatio) === false && Number.parseFloat(ltvRatio) >= 90) signals.push('ltv_ratio: ' + ltvRatio);
return [{ json: { text: [
  '==============================',
  'LOAN APPLICATION - FLAGGED FOR HUMAN REVIEW',
  '==============================',
  'Customer:    ' + fullName + ' | ID: ' + customerId,
  'Loan Amount: $' + loanAmount,
  '',
  'RISK SIGNALS DETECTED:',
  ...(signals.length ? signals.map((s) => '  ' + s) : ['  Manual review required based on risk gate trigger']),
  '',
  'AGENT FINDINGS SUMMARY:',
  '  Credit Verdict:   ' + creditVerdict,
  '  Payment Verdict:  ' + paymentVerdict,
  '  Property Verdict: ' + propertyVerdict,
  '  LTV Ratio:        ' + ltvRatio,
  '',
  'ACTION REQUIRED:',
  '  Manual underwriter review is required before any decision is issued.',
  '  Do not approve or decline without senior sign-off.',
  '',
  'Flagged by: Autonomous Risk Gate - Denodo-powered loan assessment pipeline.',
  '=============================='
].join('\n') } }];

const findings = $input.first().json.output || '';
const custMatch  = findings.match(/customer_id:\s*(\d+)/);
const nameMatch  = findings.match(/full_name:\s*([^\n]+)/);
const reasonMatch = findings.match(/sar_reasons:\s*([^\n]+)/);
const reportId = 'SAR-' + Date.now();
return [{ json: { text: [
  '==============================',
  'SUSPICIOUS ACTIVITY REPORT FILED',
  '==============================',
  'Report ID:     ' + reportId,
  'Customer ID:   ' + (custMatch  ? custMatch[1]  : 'UNKNOWN'),
  'Customer Name: ' + (nameMatch  ? nameMatch[1].trim()  : 'UNKNOWN'),
  'SAR Reasons:   ' + (reasonMatch ? reasonMatch[1].trim() : 'See findings'),
  '',
  'Compliance Findings:',
  findings,
  '',
  'IMPORTANT: Do not alert the customer. Escalated to compliance officer.',
  'Timestamp: ' + new Date().toISOString(),
  '=============================='
].join('\n') } }];

const raw = $input.first().json.output || '';
const extractJson = (text) => {
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start === -1 || end === -1 || end <= start) return null;
  try {
    return JSON.parse(text.slice(start, end + 1));
  } catch {
    return null;
  }
};
const parsed = extractJson(raw) || {};
const complaintMatches = Array.isArray(parsed.complaint_matches) ? parsed.complaint_matches : [];
const transcriptMatches = Array.isArray(parsed.transcript_matches) ? parsed.transcript_matches : [];
const toNumber = (value) => {
  const num = Number.parseFloat(value);
  return Number.isFinite(num) ? num : null;
};
const toTs = (value) => {
  if (value === null || value === undefined || value === '') return 0;
  if (typeof value === 'number' && Number.isFinite(value)) return value;
  const numeric = Number(value);
  if (Number.isFinite(numeric)) return numeric;
  const parsedDate = Date.parse(value);
  return Number.isFinite(parsedDate) ? parsedDate : 0;
};
const customers = new Map();
const ensureCustomer = (customerId) => {
  const key = String(customerId ?? 'UNKNOWN');
  if (!customers.has(key)) {
    customers.set(key, {
      customer_id: key,
      complaintCount: 0,
      transcriptCount: 0,
      unresolvedComplaintCount: 0,
      bestComplaintDistance: null,
      bestTranscriptDistance: null,
      recentComplaintTs: 0,
      recentTranscriptTs: 0,
      complaintEvidence: 'NONE',
      transcriptEvidence: 'NONE',
      relatedOfficerIds: []
    });
  }
  return customers.get(key);
};
for (const match of complaintMatches) {
  const customer = ensureCustomer(match.customer_id);
  customer.complaintCount += 1;
  const distance = toNumber(match.distance);
  if (distance !== null && (customer.bestComplaintDistance === null || distance < customer.bestComplaintDistance)) {
    customer.bestComplaintDistance = distance;
    customer.complaintEvidence = match.complaint_text || 'NONE';
  }
  const ts = toTs(match.complaint_date);
  customer.recentComplaintTs = Math.max(customer.recentComplaintTs, ts);
  if (match.resolved === false || String(match.resolved).toLowerCase() === 'false') {
    customer.unresolvedComplaintCount += 1;
  }
}
for (const match of transcriptMatches) {
  const customer = ensureCustomer(match.customer_id);
  customer.transcriptCount += 1;
  const distance = toNumber(match.distance);
  if (distance !== null && (customer.bestTranscriptDistance === null || distance < customer.bestTranscriptDistance)) {
    customer.bestTranscriptDistance = distance;
    customer.transcriptEvidence = match.transcript_text || 'NONE';
  }
  const ts = toTs(match.meeting_date);
  customer.recentTranscriptTs = Math.max(customer.recentTranscriptTs, ts);
  if (match.loan_officer_id !== undefined && match.loan_officer_id !== null && !customer.relatedOfficerIds.includes(String(match.loan_officer_id))) {
    customer.relatedOfficerIds.push(String(match.loan_officer_id));
  }
}
const now = Date.now();
const rankedCustomers = [...customers.values()].map((customer) => {
  let score = 0;
  if (customer.bestComplaintDistance !== null) score += Math.max(0, 35 - customer.bestComplaintDistance * 20);
  if (customer.bestTranscriptDistance !== null) score += Math.max(0, 35 - customer.bestTranscriptDistance * 20);
  if (customer.complaintCount > 0 && customer.transcriptCount > 0) score += 20;
  score += Math.min(customer.unresolvedComplaintCount, 3) * 4;
  const mostRecentTs = Math.max(customer.recentComplaintTs, customer.recentTranscriptTs);
  if (mostRecentTs > 0) {
    const ageDays = Math.max(0, (now - mostRecentTs) / 86400000);
    score += Math.max(0, 10 - ageDays / 30);
  }
  return {
    customer_id: customer.customer_id,
    score: Number(score.toFixed(2)),
    complaint_count: customer.complaintCount,
    transcript_count: customer.transcriptCount,
    unresolved_complaint_count: customer.unresolvedComplaintCount,
    best_complaint_distance: customer.bestComplaintDistance,
    best_transcript_distance: customer.bestTranscriptDistance,
    complaint_evidence: customer.complaintEvidence,
    transcript_evidence: customer.transcriptEvidence,
    related_officer_ids: customer.relatedOfficerIds.slice(0, 5)
  };
}).sort((a, b) => b.score - a.score || (a.best_complaint_distance ?? 999) - (b.best_complaint_distance ?? 999) || (a.best_transcript_distance ?? 999) - (b.best_transcript_distance ?? 999));
const complaintTrimmed = complaintMatches.slice().sort((a, b) => (toNumber(a.distance) ?? 999) - (toNumber(b.distance) ?? 999)).slice(0, 8);
const transcriptTrimmed = transcriptMatches.slice().sort((a, b) => (toNumber(a.distance) ?? 999) - (toNumber(b.distance) ?? 999)).slice(0, 8);
const shortlist = rankedCustomers.slice(0, 5);
return [{ json: {
  query_topic: parsed.query_topic || $json.chatInput || 'UNKNOWN',
  complaint_matches: complaintTrimmed,
  transcript_matches: transcriptTrimmed,
  candidate_customer_ids: shortlist.map((item) => item.customer_id),
  customer_rankings: shortlist,
  matched_complaints: complaintMatches.length,
  matched_transcripts: transcriptMatches.length
} }];
